"use client";

import { useCallback, useEffect, useState } from "react";
import { format, addDays } from "date-fns";
import {
  Calendar, Clock, Plus, Trash2, Save, RotateCcw, Zap, CheckCircle2,
} from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { useAuthStore } from "@/store";
import { useToast } from "@/hooks/use-toast";
import { api, API_ENDPOINTS } from "@/services/api";
import { Doctor } from "@/types";
import DashboardLayout from "@/components/layout/DashboardLayout";
import { Select } from "@/components/ui/select";

// ── Types ─────────────────────────────────────────────────────────────────────

type DayKey = "monday" | "tuesday" | "wednesday" | "thursday" | "friday" | "saturday" | "sunday";

interface DaySchedule {
  enabled: boolean;
  start: string;
  end: string;
}

type WeeklySchedule = Record<DayKey, DaySchedule>;

interface UpcomingSlot {
  id: number;
  date: string;
  start_time: string;
  end_time: string;
  is_available: boolean;
  is_recurring: boolean;
}

// ── Constants ─────────────────────────────────────────────────────────────────

const DAYS: { key: DayKey; label: string; short: string }[] = [
  { key: "monday",    label: "Monday",    short: "Mon" },
  { key: "tuesday",   label: "Tuesday",   short: "Tue" },
  { key: "wednesday", label: "Wednesday", short: "Wed" },
  { key: "thursday",  label: "Thursday",  short: "Thu" },
  { key: "friday",    label: "Friday",    short: "Fri" },
  { key: "saturday",  label: "Saturday",  short: "Sat" },
  { key: "sunday",    label: "Sunday",    short: "Sun" },
];

const TIME_OPTIONS: string[] = [];
for (let h = 0; h < 24; h++) {
  TIME_OPTIONS.push(`${String(h).padStart(2, "0")}:00`);
  TIME_OPTIONS.push(`${String(h).padStart(2, "0")}:30`);
}

const DEFAULT_SCHEDULE: WeeklySchedule = {
  monday:    { enabled: false, start: "09:00", end: "17:00" },
  tuesday:   { enabled: false, start: "09:00", end: "17:00" },
  wednesday: { enabled: false, start: "09:00", end: "17:00" },
  thursday:  { enabled: false, start: "09:00", end: "17:00" },
  friday:    { enabled: false, start: "09:00", end: "17:00" },
  saturday:  { enabled: false, start: "09:00", end: "13:00" },
  sunday:    { enabled: false, start: "09:00", end: "13:00" },
};

// ── Helpers ───────────────────────────────────────────────────────────────────

function apiScheduleToLocal(raw: Record<string, { start: string; end: string }>): WeeklySchedule {
  const result = { ...DEFAULT_SCHEDULE };
  for (const [day, val] of Object.entries(raw)) {
    const key = day as DayKey;
    if (result[key] !== undefined) {
      result[key] = { enabled: true, start: val.start, end: val.end };
    }
  }
  return result;
}

function localScheduleToApi(schedule: WeeklySchedule): Record<string, { start: string; end: string }> {
  const result: Record<string, { start: string; end: string }> = {};
  for (const [day, val] of Object.entries(schedule)) {
    if (val.enabled) result[day] = { start: val.start, end: val.end };
  }
  return result;
}

function slotCount(start: string, end: string): number {
  const [sh, sm] = start.split(":").map(Number);
  const [eh, em] = end.split(":").map(Number);
  return Math.max(0, Math.floor(((eh * 60 + em) - (sh * 60 + sm)) / 30));
}

// ── Page ──────────────────────────────────────────────────────────────────────

export default function SchedulePage() {
  const { user, setUser } = useAuthStore();
  const { toast } = useToast();
  const doctor = user as Doctor;

  const [schedule, setSchedule] = useState<WeeklySchedule>(DEFAULT_SCHEDULE);
  const [onDemand, setOnDemand] = useState(doctor?.isOnDemand ?? false);
  const [upcomingSlots, setUpcomingSlots] = useState<UpcomingSlot[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // ── Load current schedule from backend ──────────────────────────────────────
  const loadSchedule = useCallback(async () => {
    setLoading(true);
    try {
      const [availRes, slotsRes] = await Promise.all([
        api.get<{ is_on_demand: boolean; weekly_schedule: Record<string, { start: string; end: string }> }>(
          API_ENDPOINTS.DOCTOR_AVAILABILITY
        ),
        api.get<UpcomingSlot[]>(API_ENDPOINTS.DOCTOR_SLOTS),
      ]);
      setOnDemand(availRes.is_on_demand);
      setSchedule(apiScheduleToLocal(availRes.weekly_schedule ?? {}));
      setUpcomingSlots(Array.isArray(slotsRes) ? slotsRes : []);
    } catch {
      toast({ title: "Failed to load schedule", variant: "destructive" });
    } finally {
      setLoading(false);
    }
  }, [toast]);

  useEffect(() => { loadSchedule(); }, [loadSchedule]);

  // ── Save weekly schedule ─────────────────────────────────────────────────────
  const handleSave = async () => {
    setSaving(true);
    try {
      await api.patch(API_ENDPOINTS.DOCTOR_AVAILABILITY, {
        is_on_demand: onDemand,
        weekly_schedule: localScheduleToApi(schedule),
      });
      setUser({ ...doctor, isOnDemand: onDemand } as Doctor);
      toast({ title: "Schedule saved", description: "Patients can now book based on your availability." });
      loadSchedule();
    } catch (e: unknown) {
      toast({ title: "Save failed", description: e instanceof Error ? e.message : "Please try again.", variant: "destructive" });
    } finally {
      setSaving(false);
    }
  };

  // ── Toggle a day on/off ──────────────────────────────────────────────────────
  const toggleDay = (day: DayKey) =>
    setSchedule((prev) => ({ ...prev, [day]: { ...prev[day], enabled: !prev[day].enabled } }));

  // ── Update start/end time for a day ─────────────────────────────────────────
  const updateTime = (day: DayKey, field: "start" | "end", value: string) =>
    setSchedule((prev) => ({ ...prev, [day]: { ...prev[day], [field]: value } }));

  // ── Delete an explicit slot ──────────────────────────────────────────────────
  const deleteSlot = async (id: number) => {
    try {
      await api.delete(API_ENDPOINTS.DOCTOR_SLOT_DETAIL(id));
      setUpcomingSlots((prev) => prev.filter((s) => s.id !== id));
      toast({ title: "Slot removed" });
    } catch {
      toast({ title: "Failed to remove slot", variant: "destructive" });
    }
  };

  const enabledDays = DAYS.filter((d) => schedule[d.key].enabled);
  const totalWeeklySlots = enabledDays.reduce(
    (sum, d) => sum + slotCount(schedule[d.key].start, schedule[d.key].end),
    0
  );

  if (loading) {
    return (
      <DashboardLayout>
        <div className="flex items-center justify-center min-h-[400px]">
          <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary" />
        </div>
      </DashboardLayout>
    );
  }

  return (
    <DashboardLayout>
      <div className="max-w-4xl mx-auto space-y-6">

        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-2xl font-bold text-foreground">My Schedule</h1>
            <p className="text-muted-foreground text-sm mt-0.5">
              Set your weekly availability so patients can book appointments.
            </p>
          </div>
          <div className="flex gap-2">
            <Button variant="outline" size="sm" onClick={loadSchedule} disabled={saving}>
              <RotateCcw className="h-4 w-4 mr-1" /> Reset
            </Button>
            <Button size="sm" onClick={handleSave} disabled={saving} className="gradient-primary border-0">
              <Save className="h-4 w-4 mr-1" />
              {saving ? "Saving…" : "Save Schedule"}
            </Button>
          </div>
        </div>

        {/* On-demand toggle */}
        <Card className={onDemand ? "border-success/30 bg-success/5" : "border-border"}>
          <CardContent className="p-4 flex items-center justify-between gap-4">
            <div className="flex items-center gap-3">
              <div className={`h-10 w-10 rounded-xl flex items-center justify-center ${onDemand ? "bg-success/20" : "bg-muted"}`}>
                <Zap className={`h-5 w-5 ${onDemand ? "text-success" : "text-muted-foreground"}`} />
              </div>
              <div>
                <p className="font-semibold text-foreground text-sm">On-Demand Consultations</p>
                <p className="text-xs text-muted-foreground">
                  {onDemand ? "Patients can consult you instantly." : "Turn on to accept instant video consultations."}
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <Switch checked={onDemand} onCheckedChange={setOnDemand} id="on-demand" />
              <Badge className={onDemand ? "bg-success/15 text-success border-success/30" : "bg-muted text-muted-foreground"}>
                {onDemand ? "Live" : "Off"}
              </Badge>
            </div>
          </CardContent>
        </Card>

        {/* Weekly schedule */}
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <Calendar className="h-4 w-4 text-primary" />
              Weekly Availability
            </CardTitle>
            {enabledDays.length > 0 && (
              <Badge variant="secondary">
                {enabledDays.length} day{enabledDays.length !== 1 ? "s" : ""} · ~{totalWeeklySlots} slots/week
              </Badge>
            )}
          </CardHeader>
          <CardContent className="space-y-3">
            {DAYS.map(({ key, label, short }) => {
              const day = schedule[key];
              const slots = day.enabled ? slotCount(day.start, day.end) : 0;
              return (
                <div
                  key={key}
                  className={`flex flex-col sm:flex-row sm:items-center gap-3 p-3 rounded-xl border transition-colors ${
                    day.enabled ? "border-primary/30 bg-primary/5" : "border-border bg-muted/30"
                  }`}
                >
                  {/* Day toggle */}
                  <div className="flex items-center gap-3 min-w-[130px]">
                    <Switch checked={day.enabled} onCheckedChange={() => toggleDay(key)} id={`day-${key}`} />
                    <label htmlFor={`day-${key}`} className={`text-sm font-medium cursor-pointer ${day.enabled ? "text-foreground" : "text-muted-foreground"}`}>
                      <span className="hidden sm:inline">{label}</span>
                      <span className="sm:hidden">{short}</span>
                    </label>
                  </div>

                  {/* Time pickers */}
                  {day.enabled ? (
                    <div className="flex items-center gap-2 flex-1">
                      <Select
                        value={day.start}
                        onChange={(e) => updateTime(key, "start", e.target.value)}
                        className="flex-1 text-sm border border-border rounded-lg px-2 py-1.5 bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/30"
                      >
                        {TIME_OPTIONS.map((t) => (
                          <option key={t} value={t}>{t}</option>
                        ))}
                      </Select>
                      <span className="text-muted-foreground text-sm">to</span>
                      <Select
                        value={day.end}
                        onChange={(e) => updateTime(key, "end", e.target.value)}
                        className="flex-1 text-sm border border-border rounded-lg px-2 py-1.5 bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/30"
                      >
                        {TIME_OPTIONS.filter((t) => t > day.start).map((t) => (
                          <option key={t} value={t}>{t}</option>
                        ))}
                      </Select>
                      <Badge variant="secondary" className="shrink-0 text-xs">
                        {slots} slot{slots !== 1 ? "s" : ""}
                      </Badge>
                    </div>
                  ) : (
                    <p className="text-xs text-muted-foreground sm:ml-2">Not available</p>
                  )}
                </div>
              );
            })}

            {enabledDays.length === 0 && (
              <div className="text-center py-6 text-muted-foreground text-sm">
                <Calendar className="h-10 w-10 mx-auto mb-2 opacity-30" />
                Enable at least one day so patients can book appointments.
              </div>
            )}
          </CardContent>
        </Card>

        {/* Summary preview */}
        {enabledDays.length > 0 && (
          <Card className="border-primary/20 bg-primary/5">
            <CardContent className="p-4">
              <p className="text-sm font-semibold text-foreground mb-3 flex items-center gap-2">
                <CheckCircle2 className="h-4 w-4 text-primary" />
                Schedule Preview
              </p>
              <div className="grid sm:grid-cols-2 gap-2">
                {enabledDays.map(({ key, label }) => (
                  <div key={key} className="flex items-center justify-between text-sm bg-background rounded-lg px-3 py-2 border border-border">
                    <span className="font-medium text-foreground">{label}</span>
                    <span className="text-muted-foreground">
                      {schedule[key].start} – {schedule[key].end}
                      <span className="ml-2 text-xs text-primary">
                        ({slotCount(schedule[key].start, schedule[key].end)} slots)
                      </span>
                    </span>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        )}

        <Separator />

        {/* Upcoming explicit slots */}
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-3">
            <CardTitle className="text-base flex items-center gap-2">
              <Clock className="h-4 w-4 text-primary" />
              Upcoming Explicit Slots
            </CardTitle>
            <Badge variant="outline">{upcomingSlots.length} slot{upcomingSlots.length !== 1 ? "s" : ""}</Badge>
          </CardHeader>
          <CardContent>
            {upcomingSlots.length === 0 ? (
              <p className="text-sm text-muted-foreground text-center py-6">
                No explicit slots set. Your weekly schedule above generates slots automatically.
              </p>
            ) : (
              <div className="space-y-2">
                {upcomingSlots.map((slot) => (
                  <div
                    key={slot.id}
                    className={`flex items-center justify-between p-3 rounded-lg border text-sm ${
                      slot.is_available ? "border-border bg-background" : "border-destructive/30 bg-destructive/5"
                    }`}
                  >
                    <div className="flex items-center gap-3">
                      <div>
                        <p className="font-medium text-foreground">
                          {format(new Date(slot.date), "EEE, MMM d, yyyy")}
                        </p>
                        <p className="text-xs text-muted-foreground">
                          {slot.start_time.slice(0, 5)} – {slot.end_time.slice(0, 5)}
                        </p>
                      </div>
                      <div className="flex gap-1">
                        {slot.is_recurring && <Badge variant="secondary" className="text-xs">Recurring</Badge>}
                        {!slot.is_available && <Badge variant="destructive" className="text-xs">Blocked</Badge>}
                      </div>
                    </div>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8 text-muted-foreground hover:text-destructive"
                      onClick={() => deleteSlot(slot.id)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        {/* Save button (bottom) */}
        <div className="flex justify-end pb-6">
          <Button onClick={handleSave} disabled={saving} className="gradient-primary border-0 px-8">
            <Save className="h-4 w-4 mr-2" />
            {saving ? "Saving…" : "Save Schedule"}
          </Button>
        </div>
      </div>
    </DashboardLayout>
  );
}
